import { NextResponse } from "next/server";
import connectDb from "@/lib/db";
import { AuthError, requireRole } from "@/server/auth/guards";
import User from "@/models/user.model";
import { z } from "zod";

const statusSchema = z.object({
  isOnline: z.boolean(),
  latitude: z.number().optional(),
  longitude: z.number().optional(),
});

export async function POST(req: Request) {
  try {
    await connectDb();
    const userAuth = await requireRole("vendor");

    const body = await req.json();
    const { isOnline, latitude, longitude } = statusSchema.parse(body);

    const updateData: any = { isOnline };
    if (isOnline && latitude !== undefined && longitude !== undefined) {
      updateData.location = {
        type: "Point",
        coordinates: [longitude, latitude], // MongoDB requires [lng, lat]
      };
      updateData.lastLocationUpdate = new Date();
    }

    const user = await User.findByIdAndUpdate(
      userAuth.id,
      updateData,
      { new: true }
    );

    if (!user) {
      return NextResponse.json({ message: "User not found" }, { status: 404 });
    }

    const Redis = require("ioredis");
    const redis = new Redis(process.env.UPSTASH_REDIS_URL || "");

    if (isOnline && latitude !== undefined && longitude !== undefined) {
      await redis.geoadd("driver-locations", longitude, latitude, userAuth.id);
    } else if (!isOnline) {
      await redis.zrem("driver-locations", userAuth.id);
    }

    return NextResponse.json({ success: true, isOnline: user.isOnline });
  } catch (error) {
    if (error instanceof AuthError) {
      return NextResponse.json({ message: error.message }, { status: error.status });
    }
    return NextResponse.json({ message: "Server Error" }, { status: 500 });
  }
}

"use client";

import { useEffect } from "react";
import { motion } from "framer-motion";
import { AlertCircle, RefreshCcw } from "lucide-react";
import Link from "next/link";

export default function GlobalError({
  error,
  reset,
}: {
  error: Error & { digest?: string };
  reset: () => void;
}) {
  useEffect(() => {
    // Log the error to an error reporting service
    console.error(error);
  }, [error]);

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 flex flex-col items-center justify-center p-4">
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="max-w-md w-full bg-white dark:bg-gray-800 rounded-2xl shadow-xl p-8 text-center border border-gray-100 dark:border-gray-700"
      >
        <div className="w-16 h-16 bg-red-100 dark:bg-red-900/30 rounded-full flex items-center justify-center mx-auto mb-6">
          <AlertCircle className="w-8 h-8 text-red-600 dark:text-red-400" />
        </div>

        <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-3">
          Oops, something went wrong!
        </h2>

        <p className="text-gray-500 dark:text-gray-400 mb-8">
          We encountered an unexpected error while trying to process your request. Don't worry, our team has been notified.
        </p>

        <div className="flex flex-col sm:flex-row gap-4 justify-center">
          <button
            onClick={() => reset()}
            className="flex items-center justify-center gap-2 px-6 py-3 bg-gray-900 dark:bg-white text-white dark:text-gray-900 rounded-xl font-medium hover:bg-gray-800 dark:hover:bg-gray-100 transition-colors"
          >
            <RefreshCcw className="w-4 h-4" />
            Try Again
          </button>

          <Link
            href="/"
            className="flex items-center justify-center px-6 py-3 bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-xl font-medium hover:bg-gray-200 dark:hover:bg-gray-600 transition-colors"
          >
            Return Home
          </Link>
        </div>
      </motion.div>
    </div>
  );
}

